import { cursor } from './cursor';
import { gamePaused } from './game';
import { givenCells } from './history';
import { derived } from 'svelte/store';

export const keyboardDisabled = derived(
	[cursor, givenCells, gamePaused],
	([$cursor, $givenCells, $gamePaused]) => {
		return ($cursor.x === null && $cursor.y === null) || $givenCells[$cursor.y][$cursor.x] !== 0 || $gamePaused;
	},
	false,
);
